import React from 'react';
import Plot from './plot'

const Wave = () => {
  let w = 600;
  let h = 400;
  let waves = [
    {bg:"lightblue", lambda:300, amplitude: 150},
    {bg:"lightpink", lambda:400, amplitude: 100}
  ];

  return(
    <>
      {
        waves.map((wave, i)=>{
          return <Plot id={i} bg={wave.bg} width={w} wavelength={wave.lambda} height={h} amplitude={wave.amplitude}/>
        })
      }
    </>
  )
  // return <Plot id={3} bg={"lightblue"} width={600} wavelength={300} height={400} amplitude={150}/>
}

export default Wave;