import React from 'react';
import p5 from 'p5';
import './sketch.css';

const Sketch = (props)=>{
  let tabInputRef = null;
  var coords = {}
  let table = 2;
  let mul = 150; //multiple
  let r = 250
  let count = 0;

  const s = ( sketch ) => {
    sketch.getCoords = ()=>{
      for(let i = 0; i<table*mul; i++){
        let x = r + (r-10) * Math.sin(i*2*Math.PI/mul)
        let y = r + (r-10) * Math.cos(i*2*Math.PI/mul)
        sketch.ellipse(x,y,5)
        let val = i;
        coords[val] = {x:x, y:y}
      }
    }

    sketch.setup = () => {
      sketch.createCanvas(2*r, 2*r);
      sketch.background("blue");
      sketch.stroke("gold");
      sketch.strokeWeight(2)
      sketch.getCoords()

      for(let i = 0; i<mul; i++){
        // let o = coords[i];
        // let d = coords[table*i];
        // sketch.line(o.x,o.y,d.x,d.y)
      }
    };

    sketch.draw = () => {
      if(count < mul){
        let o = coords[count];
        let d = coords[table*count];
        sketch.line(o.x,o.y,d.x,d.y)
        count = count + 1;
      }
      else{
        sketch.noLoop()
      }
    };

    sketch.clearCvs = ()=>{
      sketch.background("blue");
      for(let i = 0; i<mul; i++){
        let o = coords[i];
        sketch.ellipse(o.x,o.y,5)
      }
    }
  };

  let myp5 = new p5(s, 'sketch'+props.id);
  const resetCanvas = ()=>{
    count = 0;
    myp5.clearCvs();
    myp5.loop();
  }

  const onValSelect = ()=>{
    myp5.getCoords();
    resetCanvas();
  }

  const onPresetSelect = (val)=>{
    tabInputRef.value = val;
    table = val;
    myp5.getCoords();
    resetCanvas();
  }

  let hpresets = [11,21,31,41,51,61,71,81,91,101,111,121,131,141]
  let cpresets = [6,16,26,36,46,56,66,76,86,96,106,116,126,136,146]

  return (
    <>
      <div className="container row">
        <div className="form-floating col-lg-5">
          <input className="form-control text-center" placeholder="Enter a the table" id="numberEntry"
          defaultValue={table} onChange={(e)=>{table = e.target.value}} ref={(input)=>{tabInputRef = input}}/>
          <button className="btn btn-primary m-2" onClick={()=>onValSelect()}>Redraw</button>
          <div className="col-12 rounded p-2 mt-2 border border-primary">
            {
              hpresets.map((val)=>{
                return <button className="btn btn-primary m-1" onClick={()=>onPresetSelect(val)}>{val}</button>
              })
            }
          </div>
          <div className="col-12 rounded p-2 mt-2 border border-primary">
            {
              cpresets.map((val)=>{
                return <button className="btn btn-primary m-1" onClick={()=>onPresetSelect(val)}>{val}</button>
              })
            }
          </div>

        </div>
        <div id={"sketch"+props.id} className="sketch col-lg-7"></div>
      </div>
    </>
  );
}

export default Sketch;
