import React from 'react';
import p5 from 'p5';
import './sketch.css';

const Plot = (props)=>{
  const s = ( sketch ) => {
    let x = 0;
    let h = props.height/2
    let amplitude = props.amplitude;
    let delta1 = sketch.TWO_PI / props.wavelength;
    let waves = [
      {bg:"lightblue", lambda:300, amplitude: 150},
      {bg:"lightpink", lambda:400, amplitude: 100}
    ];
  
    sketch.setup = () => {
      sketch.createCanvas(props.width, props.height);
      sketch.background(props.bg);
      sketch.frameRate(60);
      sketch.line(0, h, props.width, h);
      sketch.stroke(0);
      let count = 0;
      sketch.text("0", 0, h+10);
      sketch.text("PI", props.wavelength, h+10);
      sketch.text("2PI", 2*props.wavelength-20, h+10);  
    };
    

    sketch.draw = () => {
      waves.map((wave,i)=>{        
        sketch.stroke(100);
        let xd = x + 2;
        let delta = sketch.TWO_PI / wave.lambda;
        let src = {x: x, y: h-wave.amplitude*sketch.sin(x*delta)}
        let des = {x: xd, y: h-wave.amplitude*sketch.sin(xd*delta)}
        sketch.line(src.x, src.y, des.x, des.y);
        sketch.line(des.x, h, des.x, des.y);
        sketch.noStroke()
      })
      x = x + 2;
    };
  };

  let myp5 = new p5(s, 'sketch'+props.id);
  return (
    <div id={"sketch"+props.id} className="sketch"></div>
  );
}

export default Plot;
