import React from 'react';
import p5 from 'p5';
import './sketch.css';

const Sketch = (props)=>{
  const s = ( sketch ) => {
    let x = 75;
    let y = 75;
    let vx = props.vx;
    let vy = props.vy;
  
    sketch.setup = () => {
      sketch.createCanvas(200, 200);
      sketch.frameRate(60);
    };
    
    const updateCoords = ()=>{      
      if(vx){
        x = x+vx;
        if(x>200 || x<0){
          vx = -1*vx
        }
      }
      if(vy){
        y = y+vy;
        if(y>200 || y<0){
          vy = -1*vy
        }
      }
    }

    sketch.draw = () => {
      sketch.background(props.bg);
      sketch.fill('blue');
      sketch.noStroke();
      if(props.type === "ellipse"){
        sketch.ellipse(x,y,50,50)
      }
      else{
        sketch.rect(x,y,50,50);
      } 
      let fps = sketch.frameRate();
      sketch.fill(0);
      sketch.stroke(0);
      sketch.text("FPS: " + fps.toFixed(2), 10, 10);     
      updateCoords()
    };
  };

  let myp5 = new p5(s, 'sketch'+props.id);
  return (
    <div id={"sketch"+props.id} className="sketch"></div>
  );
}

export default Sketch;
